/* == EXEMPLE =======================================
 * Machine d'etat TCP simplifiee
 * Meme pattern : enum + struct + fonctions de transition
 * avec gardes sur l'etat courant.
 * ================================================= */
typedef enum { CLOSED, LISTEN, ESTABLISHED, CLOSE_WAIT } TcpState;

const char *example_tcp_name(TcpState s) {
    switch (s) {
        case CLOSED:      return "CLOSED";
        case LISTEN:      return "LISTEN";
        case ESTABLISHED: return "ESTABLISHED";
        case CLOSE_WAIT:  return "CLOSE_WAIT";
        default:          return "UNKNOWN";
    }
}

typedef struct { int sockfd; TcpState state; } TcpConn;

TcpConn example_make_conn(int fd) { return (TcpConn){fd, CLOSED}; }
void example_listen(TcpConn *c) { if (c->state == CLOSED) c->state = LISTEN; }
void example_accept(TcpConn *c) { if (c->state == LISTEN) c->state = ESTABLISHED; }
void example_peer_close(TcpConn *c) { if (c->state == ESTABLISHED) c->state = CLOSE_WAIT; }
void example_close(TcpConn *c) { if (c->state == CLOSE_WAIT) c->state = CLOSED; }
void example_print(const TcpConn *c) { printf("TCP fd%d: %s\n", c->sockfd, example_tcp_name(c->state)); }
